    return shipment is null ? Results.NotFound() : Results.Ok(shipment);
});

app.MapPost("/api/shipments", async (Shipment shipment, IShipmentService service) =>
{
    var created = await service.CreateShipmentAsync(shipment);
    return Results.Created($"/api/shipments/{created.TrackingNumber}", created);
}).RequireAuthorization();

app.MapPut("/api/shipments/{id}/status", async (int id, ShipmentStatus status, IShipmentService service) =>
{
