@page "/track"

<PageTitle>Track Shipment</PageTitle>

<h2>Track Your Shipment</h2>

<div class="row mb-4">
    <div class="col-md-6">
        <div class="input-group">
            <input type="text" class="form-control" placeholder="Enter tracking number" @bind="trackingNumber" @bind:event="oninput" @onkeydown="HandleKeyDown" />
            <button class="btn btn-primary" @onclick="TrackShipment" disabled="@isLoading">Track</button>
        </div>
    </div>
</div>

@if (isLoading)
{
    <p><em>Searching...</em></p>
}
else if (notFound)
{
    <div class="alert alert-warning">No shipment found with that tracking number.</div>
}
else if (shipment is not null)
{
    <div class="card">
        <div class="card-header">
            <strong>@shipment.TrackingNumber</strong>
        </div>
        <div class="card-body">
            <div class="row mb-3">
                <div class="col-md-4"><strong>Origin:</strong> @shipment.Origin</div>
                <div class="col-md-4"><strong>Destination:</strong> @shipment.Destination</div>
                <div class="col-md-4"><strong>Estimated Delivery:</strong> @(shipment.EstimatedDelivery?.ToString("MMM dd, yyyy") ?? "N/A")</div>
            </div>
            <div class="row mb-3">
                <div class="col-md-4"><strong>Status:</strong> <span class="badge @GetStatusBadgeClass(shipment.Status)">@shipment.Status</span></div>
                <div class="col-md-4"><strong>Description:</strong> @shipment.Description</div>
            </div>

            <h5 class="mt-4">Shipment Progress</h5>
            <div class="d-flex justify-content-between position-relative mt-3 mb-2">
                @foreach (var step in progressSteps)
                {
                    var isActive = (int)shipment.Status >= step.Index;
                    <div class="text-center flex-fill">
                        <div class="rounded-circle mx-auto d-flex align-items-center justify-content-center @(isActive ? "bg-success text-white" : "bg-secondary text-white")" style="width:36px;height:36px;">
                            @(step.Index + 1)
                        </div>
                        <small class="d-block mt-1">@step.Label</small>
                    </div>
                }
            </div>
        </div>
    </div>
}

@code {
    [Inject] private IShipmentService ShipmentService { get; set; } = default!;

    private string trackingNumber = string.Empty;
    private Shipment? shipment;
    private bool isLoading;
    private bool notFound;

    private readonly List<(int Index, string Label)> progressSteps =
    [
        (0, "Pending"),
        (1, "Picked Up"),
        (2, "In Transit"),
        (3, "Out for Delivery"),
        (4, "Delivered")
    ];

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
            await TrackShipment();
    }

    private async Task TrackShipment()
    {
        if (string.IsNullOrWhiteSpace(trackingNumber)) return;
        isLoading = true;
        notFound = false;
        shipment = null;

        shipment = await ShipmentService.GetShipmentByTrackingNumberAsync(trackingNumber.Trim());
        notFound = shipment is null;
        isLoading = false;
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Cancelled => "bg-danger",
        _ => "bg-secondary"
    };
}

@page "/shipments"
@attribute [Microsoft.AspNetCore.Authorization.Authorize]

<PageTitle>Shipments Dashboard</PageTitle>

<h2>Shipments Dashboard</h2>

<div class="row mb-3">
    <div class="col-md-4">
        <input type="text" class="form-control" placeholder="Search by tracking number or destination..." @bind="searchText" @bind:event="oninput" />
    </div>
    <div class="col-md-3">
        <select class="form-select" @bind="statusFilter">
            <option value="">All Statuses</option>
            @foreach (var status in Enum.GetValues<ShipmentStatus>())
            {
                <option value="@status">@status</option>
            }
        </select>
    </div>
    <div class="col-md-3">
        <a href="shipments/new" class="btn btn-success">+ New Shipment</a>
    </div>
</div>

@if (shipments is null)
{
    <p><em>Loading shipments...</em></p>
}
else
{
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Tracking Number</th>
                <th>Origin</th>
                <th>Destination</th>
                <th>Status</th>
                <th>Created</th>
                <th>Actions</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var s in FilteredShipments)
            {
                <tr>
                    <td>@s.TrackingNumber</td>
                    <td>@s.Origin</td>
                    <td>@s.Destination</td>
                    <td><span class="badge @GetStatusBadgeClass(s.Status)">@s.Status</span></td>
                    <td>@s.CreatedAt.ToString("MMM dd, yyyy")</td>
                    <td>
                        @if (s.Status != ShipmentStatus.Delivered && s.Status != ShipmentStatus.Cancelled)
                        {
                            <button class="btn btn-sm btn-outline-primary" @onclick="() => AdvanceStatus(s)">Advance Status</button>
                        }
                    </td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    [Inject] private IShipmentService ShipmentService { get; set; } = default!;

    private List<Shipment>? shipments;
    private string searchText = string.Empty;
    private string statusFilter = string.Empty;

    private IEnumerable<Shipment> FilteredShipments => (shipments ?? []).Where(s =>
    {
        var matchesSearch = string.IsNullOrWhiteSpace(searchText) ||
            s.TrackingNumber.Contains(searchText, StringComparison.OrdinalIgnoreCase) ||
            s.Destination.Contains(searchText, StringComparison.OrdinalIgnoreCase);
        var matchesStatus = string.IsNullOrWhiteSpace(statusFilter) ||
            s.Status.ToString() == statusFilter;
        return matchesSearch && matchesStatus;
    });

    protected override async Task OnInitializedAsync()
    {
        shipments = await ShipmentService.GetAllShipmentsAsync();
    }

    private async Task AdvanceStatus(Shipment shipment)
    {
        var nextStatus = (ShipmentStatus)((int)shipment.Status + 1);
        var updated = await ShipmentService.UpdateShipmentStatusAsync(shipment.Id, nextStatus);
        var index = shipments!.FindIndex(s => s.Id == updated.Id);
        if (index >= 0) shipments[index] = updated;
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Cancelled => "bg-danger",
        _ => "bg-secondary"
    };
}

@page "/shipments/new"
@attribute [Microsoft.AspNetCore.Authorization.Authorize]

<PageTitle>New Shipment</PageTitle>

<h2>Create New Shipment</h2>

<div class="row">
    <div class="col-md-6">
        <EditForm Model="newShipment" OnValidSubmit="HandleSubmit" FormName="newShipmentForm">
            <DataAnnotationsValidator />

            <div class="mb-3">
                <label class="form-label">Origin</label>
                <InputText class="form-control" @bind-Value="newShipment.Origin" />
            </div>

            <div class="mb-3">
                <label class="form-label">Destination</label>
                <InputText class="form-control" @bind-Value="newShipment.Destination" />
            </div>

            <div class="mb-3">
                <label class="form-label">Description</label>
                <InputText class="form-control" @bind-Value="newShipment.Description" />
            </div>

            <div class="mb-3">
                <label class="form-label">Customer Email</label>
                <InputText class="form-control" type="email" @bind-Value="newShipment.CustomerEmail" />
            </div>

            <button type="submit" class="btn btn-primary" disabled="@isSubmitting">Create Shipment</button>
            <a href="shipments" class="btn btn-secondary ms-2">Cancel</a>
        </EditForm>

        @if (!string.IsNullOrEmpty(successMessage))
        {
            <div class="alert alert-success mt-3">@successMessage</div>
        }
    </div>
</div>

@code {
    [Inject] private IShipmentService ShipmentService { get; set; } = default!;
    [Inject] private NavigationManager Navigation { get; set; } = default!;

    private Shipment newShipment = new();
    private bool isSubmitting;
    private string successMessage = string.Empty;

    private async Task HandleSubmit()
    {
        isSubmitting = true;
        var created = await ShipmentService.CreateShipmentAsync(newShipment);
        successMessage = $"Shipment created with tracking number: {created.TrackingNumber}";
        isSubmitting = false;
        newShipment = new();
    }
}

