                <InputText class="form-control" @bind-Value="newShipment.Origin" />
            </div>

            <div class="mb-3">
                <label class="form-label">Destination</label>
                <InputText class="form-control" @bind-Value="newShipment.Destination" />
            </div>

            <div class="mb-3">
                <label class="form-label">Description</label>
                <InputText class="form-control" @bind-Value="newShipment.Description" />
            </div>

            <div class="mb-3">
                <label class="form-label">Customer Email</label>
                <InputText class="form-control" type="email" @bind-Value="newShipment.CustomerEmail" />
            </div>

            <button type="submit" class="btn btn-primary" disabled="@isSubmitting">Create Shipment</button>
            <a href="shipments" class="btn btn-secondary ms-2">Cancel</a>
        </EditForm>

        @if (!string.IsNullOrEmpty(successMessage))
        {
            <div class="alert alert-success mt-3">@successMessage</div>
        }
    </div>
</div>

@code {
    [Inject] private IShipmentService ShipmentService { get; set; } = default!;
    [Inject] private NavigationManager Navigation { get; set; } = default!;

    private Shipment newShipment = new();
    private bool isSubmitting;
    private string successMessage = string.Empty;

    private async Task HandleSubmit()
    {
        isSubmitting = true;
        var created = await ShipmentService.CreateShipmentAsync(newShipment);
        successMessage = $"Shipment created with tracking number: {created.TrackingNumber}";
        isSubmitting = false;
        newShipment = new();
    }
}

